				new listedValue("Mud Flats", "A level tract of land, as the bed of a dry lake or an area frequently uncovered at low tide. Usually in plural.",8),
				new listedValue("Reef", "A shallow elevation composed of consolidated material that may constitute a hazard to surface navigation.",9),
				new listedValue("Ledge", "A rocky formation continuous with and fringing the shore.",10),
