				new listedValue("Knoll", "A distinct elevation with a rounded profile less than 1000m above the surrounding relief as measured from the deepest isobath that surrounds most of the feature.",14),
				new listedValue("Ridge", "An elongated elevation of varying complexity and size, generally having steep sides.",15),
				new listedValue("Seamount", "A distinct generally equidimensional elevation greater than 1000m above the surrounding relief as measured from the deepest isobath that surrounds most of the feature.",16),
				new listedValue("Pinnacle", "Any high tower or spire-shaped pillar or rock or coral, alone or cresting a summit. It may extend above the surface of the water. It may or may not be a hazard to surface navigation.",17),
				new listedValue("Abyssal Plain", "An extensive, flat, gently sloping or nearly level region at abyssal depths.",18),
				new listedValue("Plateau", "A large, relatively flat elevation that is higher than the surrounding relief with one or more relatively steep sides.",19),
				new listedValue("Spur", "A subordinate ridge protruding from a larger feature.",20),
				new listedValue("Shelf", "The flat or gently sloping region adjacent to a continent or around an island that extends from the low water line to a depth, generally about 200m, where there is a marked increase in downward slope.",21),
				new listedValue("Trough", "A long depression generally wide and flat bottomed with symmetrical and parallel sides.",22),
				new listedValue("Saddle", "A broad pass or col in a ridge, rise or other elevation.",23),
				new listedValue("Abyssal Hill", "An isolated small elevation on the deep seafloor.",24),
				new listedValue("Apron", "A gently dipping slope, with a smooth surface, commonly found around groups of islands and seamounts.",25),
