				new listedValue("Slope", "The sloping region that deepens from a shelf to the point where there is a general decrease in gradient.",48),
				new listedValue("Terrace", "A flat or gently sloping region, generally long and narrow, bounded along one edge by a steeper descending slope and along the other by a steeper ascending slope.",49),
				new listedValue("Valley", "An elongated depression that generally widens and deepens down-slope.",50),
